func NewHTTPProxyPlugin(options v1.ClientPluginOptions) (Plugin, error) {
	opts := options.(*v1.HTTPProxyPluginOptions)
	listener := NewProxyListener()

	hp := &HTTPProxy{
		l:	listener,
		opts:	opts,
	}

	hp.s = &http.Server{
		Handler:		hp,
		ReadHeaderTimeout:	60 * time.Second,
	}

	go func() {
		_ = hp.s.Serve(listener)
	}()
	return hp, nil
}
